15	export function authMiddleware(req: Request, _res: Response, next: NextFunction): void {
16	  const header = req.headers.authorization;
17	  if (!header || !header.startsWith('Bearer ')) {
18	    next(new AppError(401, UNAUTHORIZED, 'Authentication required'));
19	    return;
20	  }
21	
22	  const token = header.slice(7);
23	  try {
24	    const payload = verifyAccessToken(token);
25	    req.user = payload;
26	    next();
27	  } catch (err) {
28	    next(err);
29	  }
30	}
