32	export async function authMiddlewareWithDbCheck(
33	  req: Request,
34	  _res: Response,
35	  next: NextFunction,
36	): Promise<void> {
37	  const header = req.headers.authorization;
38	  if (!header || !header.startsWith('Bearer ')) {
39	    next(new AppError(401, UNAUTHORIZED, 'Authentication required'));
40	    return;
41	  }
42	
43	  const token = header.slice(7);
44	  try {
45	    const payload = verifyAccessToken(token);
46	
47	    const prisma = getPrisma();
48	    const user = await prisma.user.findUnique({ where: { id: payload.userId } });
49	
50	    if (!user) {
51	      next(new AppError(401, UNAUTHORIZED, 'User not found'));
52	      return;
53	    }
54	
55	    if (user.status !== 'active') {
56	      next(new AppError(403, FORBIDDEN, 'Account is not active'));
57	      return;
58	    }
59	
60	    req.user = { ...payload, role: user.role as JwtPayload['role'] };
61	    next();
62	  } catch (err) {
63	    next(err);
64	  }
65	}
