import { Router } from 'express';
import { authMiddleware, requireRole } from '../middleware/auth.middleware';
import {
  createTemplateHandler,
  listTemplatesHandler,
  updateTemplateHandler,
  sendNotificationHandler,
  listNotificationsHandler,
  markReadHandler,
  getStatsHandler,
} from '../controllers/notifications.controller';

const router = Router();

// Notifications for current user
router.get('/notifications', authMiddleware, listNotificationsHandler);
router.patch('/notifications/:id/read', authMiddleware, markReadHandler);
router.get('/notifications/stats', authMiddleware, requireRole('admin'), getStatsHandler);

// Send notification
router.post('/notifications', authMiddleware, sendNotificationHandler);

// Notification templates
router.get('/notification-templates', authMiddleware, listTemplatesHandler);
router.post('/notification-templates', authMiddleware, requireRole('admin'), createTemplateHandler);
router.patch('/notification-templates/:id', authMiddleware, requireRole('admin'), updateTemplateHandler);

export default router;
