import { Router } from 'express';
import multer from 'multer';
import { authMiddleware } from '../middleware/auth.middleware';
import {
  downloadTemplateHandler,
  uploadHandler,
  commitHandler,
  rollbackHandler,
  getBatchStatusHandler,
} from '../controllers/import.controller';

const router = Router();
const upload = multer({ storage: multer.memoryStorage() });

router.get('/import/templates/:entityType', authMiddleware, downloadTemplateHandler);
router.post('/import/upload', authMiddleware, upload.single('file'), uploadHandler);
router.post('/import/:batchId/commit', authMiddleware, commitHandler);
router.post('/import/:batchId/rollback', authMiddleware, rollbackHandler);
router.get('/import/:batchId', authMiddleware, getBatchStatusHandler);

export default router;
