15	      const duration = Date.now() - startTime;
16	      logger.info('request completed', {
17	        method: req.method,
18	        path: req.originalUrl,
19	        statusCode: res.statusCode,
20	        duration,
21	        traceId,
22	      });
23	    });
24	
25	    next();
26	  });
