85	afterAll(async () => {
86	  // Clean up itinerary items, versions, and itinerary
87	  if (itineraryId) {
88	    await prisma.itineraryItem.deleteMany({ where: { itineraryId } }).catch(() => {});
89	    await prisma.itineraryVersion.deleteMany({ where: { itineraryId } }).catch(() => {});
90	    await prisma.itinerary.deleteMany({ where: { id: itineraryId } }).catch(() => {});
