97	function evaluateRules(
98	  rules: ModelRule[],
99	  input: Record<string, unknown>,
100	): { appliedRules: { rule: string; triggered: boolean }[]; override: { prediction: unknown; confidence: number } | null } {
101	  const appliedRules: { rule: string; triggered: boolean }[] = [];
102	  let override: { prediction: unknown; confidence: number } | null = null;
103	
104	  for (const rule of rules) {
105	    let triggered = false;
106	    try {
107	      // Safe evaluation of simple conditions
108	      const fn = new Function('input', `return (${rule.condition});`);
109	      triggered = !!fn(input);
110	    } catch {
111	      triggered = false;
112	    }
113	
114	    appliedRules.push({ rule: rule.name, triggered });
115	    if (triggered && !override) {
116	      override = { prediction: rule.output.prediction, confidence: rule.output.confidence };
117	    }
118	  }
119	
120	  return { appliedRules, override };
121	}
