116	  const valid = await bcrypt.compare(password, user.passwordHash);
117	  if (!valid) {
118	    const newFailedAttempts = user.failedAttempts + 1;
119	    const updateData: Record<string, unknown> = { failedAttempts: newFailedAttempts };
120	
121	    if (newFailedAttempts >= MAX_FAILED_ATTEMPTS) {
122	      const lockUntil = new Date(Date.now() + LOCKOUT_MINUTES * 60 * 1000);
123	      updateData.lockedUntil = lockUntil;
124	      updateData.status = 'locked';
125	    }
126	
127	    await prisma.user.update({
128	      where: { id: user.id },
129	      data: updateData,
130	    });
131	
132	    throw new AppError(401, UNAUTHORIZED, 'Invalid credentials');
133	  }
134	
135	  // Reset failed attempts on success
136	  await prisma.user.update({
137	    where: { id: user.id },
138	    data: { failedAttempts: 0, lockedUntil: null, status: user.status === 'locked' ? 'active' : user.status },
139	  });
