216	  const MAX_ATTEMPTS = 3;
217	
218	  // Find pending entries that are due for processing
219	  const pendingEntries = await prisma.outboxMessage.findMany({
220	    where: {
221	      status: 'pending',
222	      OR: [
223	        { attempts: 0 }, // never attempted
224	        {
225	          attempts: { lt: MAX_ATTEMPTS },
226	          notification: {
227	            nextRetryAt: { lte: new Date() },
228	          },
229	        },
230	      ],
231	    },
232	    include: { notification: true },
233	  });
234	
