236	
237	  for (const entry of pendingEntries) {
238	    try {
239	      // Simulate delivery (in production, this would call an email/push service)
240	      // For the mock, delivery succeeds on first attempt and may fail on retries
241	      const deliverySucceeded = true;
242	
243	      if (deliverySucceeded) {
244	        await prisma.$transaction(async (tx) => {
245	          await tx.outboxMessage.update({
246	            where: { id: entry.id },
247	            data: {
248	              status: 'delivered',
249	              attempts: entry.attempts + 1,
250	              deliveredAt: new Date(),
251	            },
252	          });
253	          await tx.notification.update({
254	            where: { id: entry.notificationId },
255	            data: {
256	              delivered: true,
257	              nextRetryAt: null,
258	            },
259	          });
260	        });
261	        results.push({ id: entry.id, status: 'delivered' });
262	      }
263	    } catch (error) {
264	      const newAttempts = entry.attempts + 1;
265	      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
266	
267	      if (newAttempts >= MAX_ATTEMPTS) {
268	        await prisma.outboxMessage.update({
269	          where: { id: entry.id },
270	          data: {
271	            status: 'failed',
272	            attempts: newAttempts,
273	            lastError: errorMessage,
274	          },
275	        });
276	        results.push({ id: entry.id, status: 'failed' });
277	      } else {
278	        // Exponential backoff: attempts * 30 seconds
279	        const nextRetry = new Date(Date.now() + newAttempts * 30 * 1000);
280	        await prisma.$transaction(async (tx) => {
