51	function mockInfer(input: Record<string, unknown>, config: ModelConfig | null): {
52	  prediction: unknown;
53	  confidence: number;
54	  topFeatures: { feature: string; contribution: number }[];
55	} {
56	  const inputStr = JSON.stringify(input, Object.keys(input).sort());
57	  const hash = crypto.createHash('md5').update(inputStr).digest();
58	
59	  // Generate deterministic prediction value from input
60	  const predictionValue = hash.readUInt16BE(0) / 65535; // 0..1
61	  const confidence = 0.5 + (hash.readUInt16BE(2) / 65535) * 0.5; // 0.5..1.0
62	
63	  // Generate feature contributions from configured features or input keys
64	  const features = config?.features ?? Object.keys(input);
65	  const topFeatures: { feature: string; contribution: number }[] = [];
66	
67	  let remainingContribution = 1.0;
68	  for (let i = 0; i < Math.min(features.length, 5); i++) {
69	    const featureHash = crypto
70	      .createHash('md5')
71	      .update(`${inputStr}:${features[i]}`)
72	      .digest();
73	    const contribution =
74	      i < features.length - 1
75	        ? (featureHash.readUInt16BE(0) / 65535) * remainingContribution * 0.6
76	        : remainingContribution;
77	    topFeatures.push({
78	      feature: features[i],
79	      contribution: Math.round(contribution * 1000) / 1000,
80	    });
81	    remainingContribution -= contribution;
82	  }
83	
84	  // Sort by contribution descending
85	  topFeatures.sort((a, b) => b.contribution - a.contribution);
86	
87	  return {
88	    prediction: Math.round(predictionValue * 100) / 100,
89	    confidence: Math.round(confidence * 1000) / 1000,
90	    topFeatures,
91	  };
