{"file_path": "/home/someone/Documents/eagle-point/108/repo/unit_tests/security.spec.ts", "content": "/**
 * Unit tests for security fixes: safe rule evaluation, challenge flow,
 * idempotency concepts, rolling lockout, device cap contract.
 */

describe('Safe rule evaluator', () => {
  // Mirrors safeEvaluateCondition from model.service.ts
  function safeEvaluateCondition(condition: string, input: Record<string, unknown>): boolean {
    const match = condition.match(/^input\.(\w+)\s*(>=|<=|===|!==|>|<)\s*(.+)$/);
    if (!match) return false;
    const [, field, op, rawValue] = match;
    const fieldValue = input[field];
    let compareValue: unknown;
    const trimmed = rawValue.trim();
    if (trimmed === 'true') compareValue = true;
    else if (trimmed === 'false') compareValue = false;
    else if (/^-?\d+(\.\d+)?$/.test(trimmed)) compareValue = Number(trimmed);
    else if (/^['"].*['"]$/.test(trimmed)) compareValue = trimmed.slice(1, -1);
    else return false;
    switch (op) {
      case '>': return Number(fieldValue) > Number(compareValue);
      case '<': return Number(fieldValue) < Number(compareValue);
      case '>=': return Number(fieldValue) >= Number(compareValue);
      case '<=': return Number(fieldValue) <= Number(compareValue);
      case '===': return fieldValue === compareValue;
      case '!==': return fieldValue !== compareValue;
      default: return false;
    }
  }

  it('evaluates simple numeric comparison', () => {
    expect(safeEvaluateCondition('input.budget > 100', { budget: 200 })).toBe(true);
    expect(safeEvaluateCondition('input.budget > 100', { budget: 50 })).toBe(false);
  });

  it('evaluates equality', () => {
    expect(safeEvaluateCondition('input.category === "luxury"', { category: 'luxury' })).toBe(true);
    expect(safeEvaluateCondition('input.category === "luxury"', { category: 'budget' })).toBe(false);
  });

  it('evaluates boolean comparison', () => {
    expect(safeEvaluateCondition('input.premium === true', { premium: true })).toBe(true);
    expect(safeEvaluateCondition('input.premium === false', { premium: false })).toBe(true);
  });

  it('rejects code injection attempts', () => {
    expect(safeEvaluateCondition('process.exit(1)', {})).toBe(false);
    expect(safeEvaluateCondition('require("fs").unlinkSync("/")', {})).toBe(false);
    expect(safeEvaluateCondition('input.x; process.exit(1)', { x: 1 })).toBe(false);
    expect(safeEvaluateCondition('(function(){return true})()', {})).toBe(false);
  });

  it('rejects unsupported operators', () => {
    expect(safeEvaluateCondition('input.x == 5', { x: 5 })).toBe(false); // == not supported
    expect(safeEvaluateCondition('input.x != 5', { x: 5 })).toBe(false); // != not supported
  });

  it('handles missing field gracefully', () => {
    expect(safeEvaluateCondition('input.missing > 5', {})).toBe(false);
  });

  it('handles negative numbers', () => {
    expect(safeEvaluateCondition('input.temp < -10', { temp: -20 })).toBe(true);
    expect(safeEvaluateCondition('input.temp < -10', { temp: 0 })).toBe(false);
  });
});

describe('Rolling lockout window semantics', () => {
  it('account should unlock after 15-minute window expires', () => {
    const LOCKOUT_MINUTES = 15;
    const lockedAt = new Date(Date.now() - (LOCKOUT_MINUTES + 1) * 60 * 1000);
    const lockedUntil = new Date(lockedAt.getTime() + LOCKOUT_MINUTES * 60 * 1000);

    // lockedUntil is in the past → should be unlocked
    expect(lockedUntil <= new Date()).toBe(true);
  });

  it('account should remain locked within 15-minute window', () => {
    const LOCKOUT_MINUTES = 15;
    const lockedAt = new Date(Date.now() - 5 * 60 * 1000); // 5 min ago
    const lockedUntil = new Date(lockedAt.getTime() + LOCKOUT_MINUTES * 60 * 1000);

    // lockedUntil is still in the future → should stay locked
    expect(lockedUntil > new Date()).toBe(true);
  });

  it('failed attempts reset after window expires', () => {
    let failedAttempts = 9;
    const lockedUntil = new Date(Date.now() - 60000); // expired 1 min ago

    // Simulate reset logic
    if (lockedUntil <= new Date()) {
      failedAttempts = 0;
    }
    expect(failedAttempts).toBe(0);
  });
});

describe('Challenge token flow', () => {
  it('challenge token has 5-minute TTL', () => {
    const CHALLENGE_TTL_MS = 5 * 60 * 1000;
    const created = new Date();
    const expires = new Date(created.getTime() + CHALLENGE_TTL_MS);

    expect(expires.getTime() - created.getTime()).toBe(300000);
    expect(expires > new Date()).toBe(true);
  });

  it('rate limit allows max 3 challenges per hour', () => {
    const MAX_CHALLENGES_PER_HOUR = 3;
    let existingChallenges = 2;

    expect(existingChallenges < MAX_CHALLENGES_PER_HOUR).toBe(true);
    existingChallenges = 3;
    expect(existingChallenges < MAX_CHALLENGES_PER_HOUR).toBe(false);
  });

  it('expired challenge token is rejected', () => {
    const expiresAt = new Date(Date.now() - 60000); // expired 1 min ago
    expect(expiresAt < new Date()).toBe(true);
  });
});

describe('Device cap response contract', () => {
  it('should return 409 status code', () => {
    const EXPECTED_STATUS = 409;
    expect(EXPECTED_STATUS).toBe(409);
  });

  it('error code should be DEVICE_LIMIT_REACHED', () => {
    const code = 'DEVICE_LIMIT_REACHED';
    expect(code).toBe('DEVICE_LIMIT_REACHED');
  });
});

describe('Idempotency key behavior', () => {
  it('same key returns cached response, not duplicate operation', () => {
    const cache = new Map<string, { status: number; body: unknown }>();
    const key = 'test-key-123';

    // First request stores result
    cache.set(key, { status: 201, body: { id: 'abc' } });

    // Second request with same key returns cached
    const cached = cache.get(key);
    expect(cached).toBeDefined();
    expect(cached!.status).toBe(201);
    expect(cached!.body).toEqual({ id: 'abc' });
  });

  it('key expires after 24 hours', () => {
    const TTL_MS = 24 * 60 * 60 * 1000;
    const created = new Date();
    const expires = new Date(created.getTime() + TTL_MS);

    expect(expires.getTime() - created.getTime()).toBe(86400000);
  });

  it('different keys are independent', () => {
    const cache = new Map<string, unknown>();
    cache.set('key-a', { id: 'a' });
    cache.set('key-b', { id: 'b' });

    expect(cache.get('key-a')).toEqual({ id: 'a' });
    expect(cache.get('key-b')).toEqual({ id: 'b' });
  });
});
"}

