1	import { Request, Response, NextFunction } from 'express';
2	import { v4 as uuidv4 } from 'uuid';
3	import { getPrisma } from '../config/database';
4	import { Prisma } from '../models/prisma';
5	import { logger } from '../utils/logger';
6	
7	const MUTATING_METHODS = ['POST', 'PATCH', 'DELETE'];
8	const TTL_MS = 24 * 60 * 60 * 1000; // 24 hours
9	
10	export function idempotencyMiddleware(req: Request, res: Response, next: NextFunction): void {
11	  if (!MUTATING_METHODS.includes(req.method)) {
12	    next();
13	    return;
14	  }
15	
16	  const idempotencyKey = (req.headers['idempotency-key'] as string) || uuidv4();
17	  res.setHeader('Idempotency-Key', idempotencyKey);
18	
19	  const prisma = getPrisma();
20	
21	  prisma.idempotencyKey
22	    .findUnique({ where: { key: idempotencyKey } })
23	    .then((existing) => {
24	      if (existing && existing.expiresAt > new Date()) {
25	        const stored = existing.responseBody as { statusCode?: number; body?: unknown };
26	        const statusCode = stored.statusCode ?? 200;
27	        const body = stored.body ?? stored;
28	        res.status(statusCode).json(body);
29	        return;
30	      }
31	
32	      // Intercept res.json to capture the response
33	      const originalJson = res.json.bind(res);
34	      res.json = function captureJson(body: unknown): Response {
35	        const record = {
36	          statusCode: res.statusCode,
37	          body,
38	        };
39	
40	        prisma.idempotencyKey
41	          .upsert({
42	            where: { key: idempotencyKey },
43	            update: {
44	              responseBody: record as unknown as Prisma.InputJsonValue,
45	              expiresAt: new Date(Date.now() + TTL_MS),
46	            },
47	            create: {
48	              key: idempotencyKey,
49	              operationType: `${req.method} ${req.path}`,
50	              responseBody: record as unknown as Prisma.InputJsonValue,
51	              expiresAt: new Date(Date.now() + TTL_MS),
52	            },
53	          })
54	          .catch((err) => {
55	            logger.error('Failed to store idempotency key', { error: (err as Error).message });
56	          });
57	
58	        return originalJson(body);
59	      };
60	
61	      next();
62	    })
63	    .catch((err) => {
64	      logger.error('Idempotency key lookup failed', { error: (err as Error).message });
65	      next();
66	    });
67	}
68

1	import bcrypt from 'bcryptjs';
2	import jwt from 'jsonwebtoken';
3	import { v4 as uuidv4 } from 'uuid';
4	import { getPrisma } from '../config/database';
5	import { env } from '../config/environment';
6	import { authConfig } from '../config/auth';
7	import { encrypt, decrypt, hashSha256 } from '../utils/crypto';
8	import { AppError, VALIDATION_ERROR, UNAUTHORIZED, CONFLICT, NOT_FOUND, RATE_LIMITED } from '../utils/errors';
9	import { JwtPayload, TokenPair, UserRole } from '../types/auth.types';
10	
11	const BCRYPT_ROUNDS = 12;
12	const MAX_DEVICES = 5;
13	const MAX_FAILED_ATTEMPTS = 10;
14	const LOCKOUT_MINUTES = 15;
15	const PASSWORD_HISTORY_COUNT = 5;
16	
17	export function validatePasswordPolicy(password: string): void {
18	  if (password.length < 12) {
19	    throw new AppError(400, VALIDATION_ERROR, 'Password must be at least 12 characters');
20	  }
21	  if (!/[A-Z]/.test(password)) {
22	    throw new AppError(400, VALIDATION_ERROR, 'Password must contain at least one uppercase letter');
23	  }
24	  if (!/[a-z]/.test(password)) {
25	    throw new AppError(400, VALIDATION_ERROR, 'Password must contain at least one lowercase letter');
26	  }
27	  if (!/[0-9]/.test(password)) {
28	    throw new AppError(400, VALIDATION_ERROR, 'Password must contain at least one digit');
29	  }
30	  if (!/[^A-Za-z0-9]/.test(password)) {
31	    throw new AppError(400, VALIDATION_ERROR, 'Password must contain at least one special character');
32	  }
33	}
34	
35	export function signAccessToken(payload: Omit<JwtPayload, 'iat' | 'exp'>): string {
36	  return jwt.sign(payload, env.jwtSecret, {
37	    algorithm: authConfig.algorithm,
38	    expiresIn: authConfig.accessTokenTtl,
39	  });
40	}
41	
42	export function signRefreshToken(): string {
43	  return uuidv4() + '-' + uuidv4();
44	}
45	
46	export function verifyAccessToken(token: string): JwtPayload {
47	  try {
48	    return jwt.verify(token, env.jwtSecret, {
49	      algorithms: [authConfig.algorithm],
50	    }) as JwtPayload;
51	  } catch {
52	    throw new AppError(401, UNAUTHORIZED, 'Invalid or expired token');
53	  }
54	}
55	
56	export async function register(
57	  username: string,
58	  password: string,
59	  securityQuestions: Array<{ question: string; answer: string }>,
60	): Promise<{ id: string; username: string }> {
61	  const prisma = getPrisma();
62	
63	  validatePasswordPolicy(password);
64	
65	  if (!securityQuestions || securityQuestions.length !== 2) {
66	    throw new AppError(400, VALIDATION_ERROR, 'Exactly 2 security questions are required');
67	  }
68	
69	  const existing = await prisma.user.findUnique({ where: { username } });
70	  if (existing) {
71	    throw new AppError(409, CONFLICT, 'Username already taken');
72	  }
73	
74	  const passwordHash = await bcrypt.hash(password, BCRYPT_ROUNDS);
75	
76	  const user = await prisma.user.create({
77	    data: {
78	      username,
79	      passwordHash,
80	      securityQuestions: {
81	        create: securityQuestions.map((sq) => ({
82	          question: sq.question,
83	          answerEncrypted: encrypt(sq.answer.trim().toLowerCase()),
84	        })),
85	      },
86	      passwordHistory: {
87	        create: { passwordHash },
88	      },
89	    },
90	  });
91	
92	  return { id: user.id, username: user.username };
93	}
94	
95	export async function login(
96	  username: string,
97	  password: string,
98	  deviceFingerprint?: string,
99	  lastKnownCity?: string,
100	  challengeToken?: string,
101	): Promise<{ tokens: TokenPair; user: { id: string; username: string; role: string } } | { challengeToken: string; retryAfterSeconds: number; message: string }> {
102	  const prisma = getPrisma();
103	
104	  const user = await prisma.user.findUnique({ where: { username } });
105	  if (!user) {
106	    throw new AppError(401, UNAUTHORIZED, 'Invalid credentials');
107	  }
108	
109	  // Rolling lockout window: if lockedUntil has passed, reset the counter
110	  if (user.lockedUntil && user.lockedUntil <= new Date()) {
111	    await prisma.user.update({
112	      where: { id: user.id },
113	      data: { failedAttempts: 0, lockedUntil: null, status: 'active' },
114	    });
115	    user.failedAttempts = 0;
116	    user.lockedUntil = null;
117	    user.status = 'active';
118	  }
119	
120	  if (user.status === 'locked' || (user.lockedUntil && user.lockedUntil > new Date())) {
121	    throw new AppError(423, 'ACCOUNT_LOCKED', 'Account is locked. Try again later.');
122	  }
123	
124	  if (user.status === 'suspended') {
125	    throw new AppError(403, 'FORBIDDEN', 'Account is suspended');
126	  }
127	
128	  const valid = await bcrypt.compare(password, user.passwordHash);
129	  if (!valid) {
130	    const newFailedAttempts = user.failedAttempts + 1;
131	    const updateData: Record<string, unknown> = { failedAttempts: newFailedAttempts };
132	
133	    if (newFailedAttempts >= MAX_FAILED_ATTEMPTS) {
134	      // Lock for LOCKOUT_MINUTES — this is the rolling window
135	      const lockUntil = new Date(Date.now() + LOCKOUT_MINUTES * 60 * 1000);
136	      updateData.lockedUntil = lockUntil;
137	      updateData.status = 'locked';
138	    }
139	
140	    await prisma.user.update({
141	      where: { id: user.id },
142	      data: updateData,
143	    });
144	
145	    throw new AppError(401, UNAUTHORIZED, 'Invalid credentials');
146	  }
147	
148	  // Reset failed attempts on success
149	  await prisma.user.update({
150	    where: { id: user.id },
151	    data: { failedAttempts: 0, lockedUntil: null, status: user.status === 'locked' ? 'active' : user.status },
152	  });
153	
154	  // Device registration
155	  const fpHash = deviceFingerprint
156	    ? hashSha256(deviceFingerprint)
157	    : hashSha256(uuidv4());
158	
159	  let device = await prisma.device.findUnique({
160	    where: { userId_fingerprintHash: { userId: user.id, fingerprintHash: fpHash } },
161	  });
162	
163	  if (!device) {
164	    const deviceCount = await prisma.device.count({ where: { userId: user.id } });
165	    if (deviceCount >= MAX_DEVICES) {
