102	/**
103	 * Deterministic mock inference: produces stable output from input hash.
104	 * Used as fallback when real adapter runtime is not available.
105	 */
106	function mockInferFn(input: Record<string, unknown>, config: ModelConfig | null): AdapterResult {
107	  const inputStr = JSON.stringify(input, Object.keys(input).sort());
108	  const hash = crypto.createHash('md5').update(inputStr).digest();
109	
110	  // Generate deterministic prediction value from input
111	  const predictionValue = hash.readUInt16BE(0) / 65535; // 0..1
112	  const confidence = 0.5 + (hash.readUInt16BE(2) / 65535) * 0.5; // 0.5..1.0
113	
114	  // Generate feature contributions from configured features or input keys
115	  const features = config?.features ?? Object.keys(input);
116	  const topFeatures: { feature: string; contribution: number }[] = [];
117	
118	  let remainingContribution = 1.0;
119	  for (let i = 0; i < Math.min(features.length, 5); i++) {
120	    const featureHash = crypto
121	      .createHash('md5')
122	      .update(`${inputStr}:${features[i]}`)
123	      .digest();
124	    const contribution =
125	      i < features.length - 1
126	        ? (featureHash.readUInt16BE(0) / 65535) * remainingContribution * 0.6
127	        : remainingContribution;
128	    topFeatures.push({
129	      feature: features[i],
130	      contribution: Math.round(contribution * 1000) / 1000,
131	    });
132	    remainingContribution -= contribution;
133	  }
134	
135	  // Sort by contribution descending
136	  topFeatures.sort((a, b) => b.contribution - a.contribution);
137	
138	  return {
139	    prediction: Math.round(predictionValue * 100) / 100,
140	    confidence: Math.round(confidence * 1000) / 1000,
141	    topFeatures,
142	  };
143	}
