145	/**
146	 * Safely evaluate a simple condition of the form "input.field op value".
147	 * Only supports comparison operators and field access — no arbitrary code execution.
148	 */
149	function safeEvaluateCondition(condition: string, input: Record<string, unknown>): boolean {
150	  // Parse "input.field op value" patterns only
151	  const match = condition.match(/^input\.(\w+)\s*(>=|<=|===|!==|>|<)\s*(.+)$/);
152	  if (!match) return false;
153	
154	  const [, field, op, rawValue] = match;
155	  const fieldValue = input[field];
156	
157	  // Parse the comparison value
158	  let compareValue: unknown;
159	  const trimmed = rawValue.trim();
160	  if (trimmed === 'true') compareValue = true;
161	  else if (trimmed === 'false') compareValue = false;
162	  else if (/^-?\d+(\.\d+)?$/.test(trimmed)) compareValue = Number(trimmed);
163	  else if (/^['"].*['"]$/.test(trimmed)) compareValue = trimmed.slice(1, -1);
164	  else return false;
165	
166	  switch (op) {
167	    case '>': return Number(fieldValue) > Number(compareValue);
168	    case '<': return Number(fieldValue) < Number(compareValue);
169	    case '>=': return Number(fieldValue) >= Number(compareValue);
170	    case '<=': return Number(fieldValue) <= Number(compareValue);
171	    case '===': return fieldValue === compareValue;
172	    case '!==': return fieldValue !== compareValue;
173	    default: return false;
174	  }

