import crypto from 'crypto';
import { v4 as uuidv4 } from 'uuid';
import { getPrisma } from '../config/database';
import { Prisma } from '../models/prisma';
import { logger } from '../utils/logger';
import { AppError, IDEMPOTENCY_CONFLICT } from '../utils/errors';

const MUTATING_METHODS = new Set(['POST', 'PATCH', 'DELETE']);
const TTL_MS = 24 * 60 * 60 * 1000; // 24 hours

/**
 * Build a fingerprint that binds an idempotency key to a specific request context.
 * Same key + different fingerprint = conflict (409).
 */
function buildFingerprint(req: Request): string {
  const actor = req.user?.userId ?? 'anonymous';
  const method = req.method;
  // Normalize route: replace UUID-like segments with :id
  const route = req.route?.path
    ? `${req.baseUrl}${req.route.path}`
    : req.originalUrl.replace(/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/gi, ':id');
  const bodyHash = req.body && Object.keys(req.body).length > 0
    ? crypto.createHash('sha256').update(JSON.stringify(req.body, Object.keys(req.body).sort())).digest('hex')
    : 'empty';
  return crypto.createHash('sha256').update(`${actor}:${method}:${route}:${bodyHash}`).digest('hex');
}

export async function idempotencyMiddleware(
  req: Request,
  res: Response,
  next: NextFunction,
): Promise<void> {
  if (!MUTATING_METHODS.has(req.method)) {
    next();
    return;
  }

  const idempotencyKey = req.headers['idempotency-key'] as string | undefined;
  if (!idempotencyKey) {
    // No key provided — proceed without idempotency tracking
    next();
    return;
  }

  res.setHeader('Idempotency-Key', idempotencyKey);
  const fingerprint = buildFingerprint(req);

  try {
    const prisma = getPrisma();
    const existing = await prisma.idempotencyKey.findUnique({ where: { key: idempotencyKey } });

    if (existing && existing.expiresAt > new Date()) {
      // Key exists and not expired — check fingerprint match
      const stored = existing.responseBody as Record<string, unknown>;
      const storedFingerprint = stored._fingerprint as string | undefined;

      if (storedFingerprint && storedFingerprint !== fingerprint) {
        // Same key, different context (actor/method/route/payload) = conflict
        res.status(409).json({
          statusCode: 409,
          code: IDEMPOTENCY_CONFLICT,
          message: 'Idempotency key already used with different request parameters',
        });
        return;
      }

      // Fingerprint matches — replay stored response
      const statusCode = (stored._statusCode as number) ?? 200;
      const body = stored._body ?? {};
      res.status(statusCode).json(body);
      return;
    }

    // No existing record or expired — intercept response to capture it
    const originalJson = res.json.bind(res);
    const originalSend = res.send.bind(res);

    let captured = false;
    const captureResponse = (body: unknown) => {
      if (captured) return;
      captured = true;

      const record = {
        _statusCode: res.statusCode,
        _body: body,
        _fingerprint: fingerprint,
      };

      prisma.idempotencyKey.upsert({
        where: { key: idempotencyKey },
        update: {
          responseBody: record as unknown as Prisma.InputJsonValue,
          expiresAt: new Date(Date.now() + TTL_MS),
        },
        create: {
          key: idempotencyKey,
          operationType: `${req.method} ${req.originalUrl.replace(/[0-9a-f-]{36}/gi, ':id')}`,
          responseBody: record as unknown as Prisma.InputJsonValue,
          expiresAt: new Date(Date.now() + TTL_MS),
        },
      }).catch((err) => {
        logger.error('Failed to store idempotency key', { error: (err as Error).message });
      });
    };

    res.json = function interceptJson(body: unknown): Response {
      captureResponse(body);
      return originalJson(body);
    };

    res.send = function interceptSend(body?: unknown): Response {
      // Capture for non-JSON responses (e.g. 204 no content)
      if (res.statusCode === 204 || !body) {
        captureResponse(null);
      }
      return originalSend(body);
    } as typeof res.send;

    next();
  } catch (err) {
    logger.error('Idempotency middleware error', { error: (err as Error).message });
    next();
  }
}
