  1	import { Request, Response, NextFunction } from 'express';
  2	import crypto from 'crypto';
  3	import { v4 as uuidv4 } from 'uuid';
  4	import { getPrisma } from '../config/database';
  5	import { Prisma } from '../models/prisma';
  6	import { logger } from '../utils/logger';
  7	import { AppError, IDEMPOTENCY_CONFLICT } from '../utils/errors';
  8	
  9	const MUTATING_METHODS = new Set(['POST', 'PATCH', 'DELETE']);
 10	const TTL_MS = 24 * 60 * 60 * 1000; // 24 hours
 11	
 12	/**
 13	 * Build a fingerprint that binds an idempotency key to a specific request context.
 14	 * Same key + different fingerprint = conflict (409).
 15	 */
 16	function buildFingerprint(req: Request): string {
 17	  // Use JWT subject from Authorization header for actor identity.
 18	  // This works regardless of whether authMiddleware has run yet.
 19	  const authHeader = req.headers.authorization;
 20	  let actor = 'anonymous';
 21	  if (authHeader?.startsWith('Bearer ')) {
 22	    try {
 23	      const payload = JSON.parse(Buffer.from(authHeader.slice(7).split('.')[1], 'base64').toString());
 24	      actor = payload.userId || 'anonymous';
 25	    } catch { /* malformed token — treat as anonymous */ }
 26	  }
 27	  const method = req.method;
 28	  // Normalize route: replace UUID-like segments with :id
 29	  const route = req.route?.path
 30	    ? `${req.baseUrl}${req.route.path}`
 31	    : req.originalUrl.replace(/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/gi, ':id');
 32	  const bodyHash = req.body && Object.keys(req.body).length > 0
 33	    ? crypto.createHash('sha256').update(JSON.stringify(req.body, Object.keys(req.body).sort())).digest('hex')
 34	    : 'empty';
 35	  return crypto.createHash('sha256').update(`${actor}:${method}:${route}:${bodyHash}`).digest('hex');
 36	}
 37	
 38	export async function idempotencyMiddleware(
 39	  req: Request,
 40	  res: Response,
 41	  next: NextFunction,
 42	): Promise<void> {
 43	  if (!MUTATING_METHODS.has(req.method)) {
 44	    next();
 45	    return;
 46	  }
 47	
 48	  const idempotencyKey = req.headers['idempotency-key'] as string | undefined;
 49	  if (!idempotencyKey) {
 50	    // No key provided — proceed without idempotency tracking
 51	    next();
 52	    return;
 53	  }
 54	
 55	  res.setHeader('Idempotency-Key', idempotencyKey);
 56	  const fingerprint = buildFingerprint(req);
 57	
 58	  try {
 59	    const prisma = getPrisma();
 60	    const existing = await prisma.idempotencyKey.findUnique({ where: { key: idempotencyKey } });
 61	
 62	    if (existing && existing.expiresAt > new Date()) {
 63	      // Key exists and not expired — check fingerprint match
 64	      const stored = existing.responseBody as Record<string, unknown>;
 65	      const storedFingerprint = stored._fingerprint as string | undefined;
 66	
 67	      if (storedFingerprint && storedFingerprint !== fingerprint) {
 68	        // Same key, different context (actor/method/route/payload) = conflict
 69	        res.status(409).json({
 70	          statusCode: 409,
 71	          code: IDEMPOTENCY_CONFLICT,
 72	          message: 'Idempotency key already used with different request parameters',
 73	        });
 74	        return;
 75	      }
 76	
 77	      // Fingerprint matches — replay stored response
 78	      const statusCode = (stored._statusCode as number) ?? 200;
 79	      const body = stored._body ?? {};
 80	      res.status(statusCode).json(body);
 81	      return;
 82	    }
 83	
 84	    // No existing record or expired — intercept response to capture it
 85	    const originalJson = res.json.bind(res);
 86	    const originalSend = res.send.bind(res);
 87	
 88	    let captured = false;
 89	    const captureResponse = (body: unknown) => {
 90	      if (captured) return;
 91	      captured = true;
 92	
 93	      const record = {
 94	        _statusCode: res.statusCode,
 95	        _body: body,
 96	        _fingerprint: fingerprint,
 97	      };
 98	
 99	      prisma.idempotencyKey.upsert({
100	        where: { key: idempotencyKey },
101	        update: {
102	          responseBody: record as unknown as Prisma.InputJsonValue,
103	          expiresAt: new Date(Date.now() + TTL_MS),
104	        },
105	        create: {
106	          key: idempotencyKey,
107	          operationType: `${req.method} ${req.originalUrl.replace(/[0-9a-f-]{36}/gi, ':id')}`,
108	          responseBody: record as unknown as Prisma.InputJsonValue,
109	          expiresAt: new Date(Date.now() + TTL_MS),
110	        },
111	      }).catch((err) => {
112	        logger.error('Failed to store idempotency key', { error: (err as Error).message });
113	      });
114	    };
115	
116	    res.json = function interceptJson(body: unknown): Response {
117	      captureResponse(body);
118	      return originalJson(body);
119	    };
120	
121	    res.send = function interceptSend(body?: unknown): Response {
122	      // Capture for non-JSON responses (e.g. 204 no content)
123	      if (res.statusCode === 204 || !body) {
124	        captureResponse(null);
125	      }
126	      return originalSend(body);
127	    } as typeof res.send;
128	
129	    next();
130	  } catch (err) {
131	    logger.error('Idempotency middleware error', { error: (err as Error).message });
132	    next();
133	  }
134	}

